
import { defineComponent, onMounted, computed } from 'vue';
import { useStore } from 'vuex';
import AppControls from '@/components/AppControls.vue';
import AppCard from '@/components/AppCard.vue';
import { pawns, crops, soil, drugs, images } from '@/data/rimworldData';
import AppCheckbox from '@/components/AppCheckbox.vue';
import { Mode } from '@/types/rimworldTypes';
import { isObjectNotEmpty } from '@/helpers';

export default defineComponent({
	name: 'RimworldPlanner',
	components: { AppControls, AppCard, AppCheckbox },
	setup() {
		//Internal
		const store = useStore();
		let changeTimer = undefined as number | undefined;
		const drugNames = drugs.map((drug) => drug.name);
		//Computed
		const filteredPawns = computed(() => {
			return pawns.filter(
				(value, index) => !store.state.rimworld.filter[index]
			);
		});
		const formattedResult = computed(() => {
			const result = store.getters['rimworld/result'];
			const meat = result.meat ? result.meat.toFixed(2) : '';
			const meatRatio = result.meat / result.production.nut || 0;
			const nut = result.production.nut ? result.production.nut.toFixed(2) : '';
			return {
				...result,
				meat,
				meatRatio: `${(meatRatio * 100).toFixed(0)}%`,
				production: {
					...result.production,
					nut,
				},
			};
		});
		const cropImages = computed(() => {
			const result: { [k: string]: any } = {};
			for (const crop of crops) {
				result[crop.name] = crop.image;
			}
			return result;
		});
		//Methods
		const add = () => {
			store.commit('rimworld/addNewItem');
		};
		const save = () => {
			store.dispatch('rimworld/saveToStorage');
		};
		const reset = () => {
			store.dispatch('rimworld/clearStorage');
		};
		const moveItem = (index: number, newIndex: number) => {
			clearTimeout(changeTimer);
			changeTimer = setTimeout(() => {
				store.dispatch('rimworld/moveItem', { index, newIndex });
			}, 500);
		};
		const removeItem = (index: number) => {
			store.commit('rimworld/removeItem', { index });
		};
		const changeProp = (
			index: number,
			prop: string,
			value: string | number | boolean
		) => {
			clearTimeout(changeTimer);
			let timeout = 0;
			if (prop === 'name') {
				timeout = 500;
			} else if (typeof value === 'number') {
				timeout = 500;
			} else if (prop === 'useMeat') {
				value = store.state.rimworld.data[index].useMeat ? false : true;
			}
			changeTimer = setTimeout(() => {
				store.dispatch('rimworld/changeProp', {
					index,
					prop,
					value,
				});
			}, timeout);
		};
		const changeSetting = (prop: string, value: string | number) => {
			clearTimeout(changeTimer);
			let timeout = 0;
			if (typeof value === 'number') {
				timeout = 500;
			}
			changeTimer = setTimeout(() => {
				store.commit('rimworld/changeSetting', { prop, value });
			}, timeout);
		};
		const toggleFilter = (index: number) => {
			store.commit('rimworld/toggleFilter', index);
		};
		//Hooks
		onMounted(() => {
			store.dispatch('rimworld/loadFromStorage');
		});
		return {
			store,
			images,
			cropImages,
			drugNames,
			drugs,
			soil,
			modes: Mode,
			filteredPawns,
			result: formattedResult,
			add,
			save,
			reset,
			removeItem,
			moveItem,
			changeProp,
			changeSetting,
			toggleFilter,
			isNotEmpty: isObjectNotEmpty,
		};
	},
});
